1	// Assembles the per-arch entry path and exception vectors into the kernel.
2	//
3	// .S files go through clang (cross-targeted at the kernel triple) and the
4	// resulting .o files are passed straight to the linker via cargo:rustc-link-arg.
5	// We deliberately *avoid* the cc crate's static-library packaging because the
6	// linker's archive member resolution wouldn't pull in `_start` (it's only
7	// referenced via the linker-script `ENTRY` directive, not from any Rust
8	// symbol). Direct .o linkage sidesteps that, and it also dodges the
9	// macOS-ar/ELF-object mismatch entirely.
10	
11	use std::path::PathBuf;
12	use std::process::Command;
13	
14	fn main() {
15	    let arch =
16	        std::env::var("CARGO_CFG_TARGET_ARCH").expect("CARGO_CFG_TARGET_ARCH unset");
17	    let out_dir = PathBuf::from(std::env::var_os("OUT_DIR").expect("OUT_DIR unset"));
18	
19	    match arch.as_str() {
20	        "aarch64" => {
21	            let sources = ["src/arch/aarch64/entry.S", "src/arch/aarch64/vectors.S"];
22	            for src in &sources {
