pub static CURRENT_PROC_NR: AtomicI32 = AtomicI32::new(i32::MIN);

/// SAFETY: caller holds the single-threaded-boot invariant; the returned
/// reference is `&'static mut` and must not be aliased.
pub unsafe fn current_proc_mut() -> Option<&'static mut Proc> {
    let n = CURRENT_PROC_NR.load(Ordering::Relaxed);
    if n == i32::MIN { return None; }
    unsafe { proc_slot_mut(ProcNr::new(n)) }
}

unsafe extern "C" {
    /// Defined in trap.S. Restores `regs` into the CPU and executes `eret`.
    fn el1_return_to_user(regs: *mut crate::arch::ArchRegisterFrame) -> !;
}

/// SAFETY: see `el1_return_to_user`; `p` must be fully initialized and
/// TTBR0 must already point at a page table that maps `p.regs.elr_el1`
/// and `p.regs.sp_el0`.
pub unsafe fn switch_to_user(p: &mut Proc) -> ! {
    CURRENT_PROC_NR.store(p.nr.get(), Ordering::Relaxed);
    // Park &mut p.regs in TPIDR_EL1 so the SVC stub finds it without a
    // table walk.
    let regs_ptr: *mut crate::arch::ArchRegisterFrame = &mut p.regs;
    // SAFETY: TPIDR_EL1 is EL1-only, never read by Rust at EL0.
    unsafe {
        core::arch::asm!("msr tpidr_el1, {0}", in(reg) regs_ptr, options(nomem, nostack));
    }
    // SAFETY: assembly contract documented at el1_return_to_user.
    unsafe { el1_return_to_user(regs_ptr) }
}
