//! IPC subsystem skeleton.
//!
//! Slice 2.3 ships only `do_ipc` as an observable stub that prints the
//! incoming primitive number; the real `mini_send` / `mini_receive` land
//! in slice 2.5.

use core::fmt::Write;
use core::sync::atomic::{AtomicU32, Ordering};

use crate::arch::ArchRegisterFrame;
use crate::uart::Uart;

