//! Fixed-size IPC message.
//!
//! The 104-byte layout matches MINIX 3's `sizeof(message) == 104` assertion
//! for `__x86_64__` (see `include/minix/ipc.h`). Both x86_64 and aarch64 ports
//! of MINIX 4 adopt the same size so that the message is ABI-portable.
//!
//! The struct is explicitly 8-aligned. MINIX 3's `message` is a union over
//! sub-structs containing `uint64_t` fields, so its native alignment is 8.
//! MINIX 4 expresses `payload` as `[u8; 96]` for now, but future typed
//! accessor structs (slice 2.5) will overlay payload regions that contain
//! `u64` fields. Forcing the message itself to 8-align guarantees those
//! overlays are 8-aligned relative to the message base — required for
//! strict-alignment loads on aarch64.
//!
//! Typed access — MINIX 3 had a union over many `mess_*` payload variants
//! (`m1i1`, `m2l1`, etc.). MINIX 4 will eventually expose strongly-typed
//! accessor structs per call (e.g., `as_vfs_read()`), but those live in the
//! servers/userland crates so the kernel doesn't pull in every protocol
//! definition. For now, `payload` is a raw byte array that callers
//! interpret per-call.

use crate::endpoint::Endpoint;

/// 104-byte fixed-size IPC message. Layout matches MINIX 3 x86_64.
#[repr(C, align(8))]
#[derive(Copy, Clone, Debug)]
pub struct Message {
    /// Endpoint of the sender (set by the kernel on delivery).
    pub m_source: Endpoint,
    /// Call number on send; result code on reply.
    pub m_type: i32,
    /// Raw payload — interpreted per-call by typed accessors.
    pub payload: [u8; 96],
}

// Compile-time guarantee that the layout matches MINIX 3's x86_64 message.
const _: () = assert!(core::mem::size_of::<Message>() == 104);
const _: () = assert!(core::mem::align_of::<Message>() == 8);

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn message_is_104_bytes() {
        assert_eq!(core::mem::size_of::<Message>(), 104);
    }

    #[test]
    fn message_align_is_8() {
        assert_eq!(core::mem::align_of::<Message>(), 8);
    }

    #[test]
    fn message_payload_offset_is_8() {
        let m = Message { m_source: 0, m_type: 0, payload: [0; 96] };
        let base = &m as *const _ as usize;
        let payload = m.payload.as_ptr() as usize;
        assert_eq!(payload - base, 8);
    }
}

// IoRange/MemRange fields and several constants are forward declarations for
// slice 2.6 (kernel-call dispatch) — they are written by `proc::init` and read
// once slices 2.5/2.6 wire up IPC and `SYS_*` handlers.
#![allow(dead_code)]

//! Privilege-table entry.
//!
//! Mirrors MINIX 3 `kernel/priv.h`'s `struct priv` with the same simplifications
//! as [`Proc`]: no SMP, no live update, no profiling. The bitmaps are sized to
//! `NR_SYS_PROCS` (for IPC / notify / asyn target maps) and `NR_SYS_CALLS`
//! (for the kernel-call mask).
//!
//! [`Proc`]: super::Proc

use arrayvec::ArrayVec;

use minix4_kernel_shared::callnr::NR_SYS_CALLS;
use minix4_kernel_shared::com::NR_SYS_PROCS;
use minix4_kernel_shared::endpoint::{Endpoint, NONE};
use minix4_kernel_shared::sys_limits::{NR_IO_RANGE, NR_IRQ, NR_MEM_RANGE};
use minix4_kernel_shared::{PrivId, ProcNr};

/// Number of `u32` chunks needed to cover `NR_SYS_PROCS` bits.
pub const IPC_MAP_CHUNKS: usize = NR_SYS_PROCS / 32;
/// Number of `u32` chunks needed to cover `NR_SYS_CALLS` bits.
pub const K_CALL_MASK_CHUNKS: usize = NR_SYS_CALLS / 32;

const _: () = assert!(NR_SYS_PROCS % 32 == 0);

/// I/O port range a privileged process may access.
#[derive(Copy, Clone, Debug, Default)]
pub struct IoRange {
    pub base: u64,
    pub count: u64,
}

/// Physical memory range a privileged process may map.
#[derive(Copy, Clone, Debug, Default)]
pub struct MemRange {
    pub base: u64,
    pub count: u64,
}

/// One slot in the kernel's privilege table.
///
/// Each system (privileged) process owns exactly one `Priv`; user processes
/// share a single user-class slot (`USER_PRIV_ID`).
#[repr(C)]
pub struct Priv {
    /// Slot index into the privilege table.
    pub id: PrivId,
    /// Process this slot belongs to, if any.
    pub proc_nr: Option<ProcNr>,
    /// Privilege flags (`PREEMPTIBLE`, `SYS_PROC`, …).
    pub flags: u16,
    /// Trap mask — bit `i` allows IPC primitive `i`.
    pub trap_mask: u16,

    // ----- IPC target / pending bitmaps ------------------------------------
    /// Bitmap of privileged slots this process may send to.
    pub ipc_to: [u32; IPC_MAP_CHUNKS],
    /// Bitmap of allowed kernel calls.
    pub k_call_mask: [u32; K_CALL_MASK_CHUNKS],
    /// Bitmap of pending notifications.
    pub notify_pending: [u32; IPC_MAP_CHUNKS],
    /// Bitmap of pending async messages.
    pub asyn_pending: [u32; IPC_MAP_CHUNKS],

    /// Signal manager endpoint (delivers signals raised against us).
    pub sig_mgr: Endpoint,

    // ----- Resource ownership ---------------------------------------------
    pub io_ranges: ArrayVec<IoRange, NR_IO_RANGE>,
    pub mem_ranges: ArrayVec<MemRange, NR_MEM_RANGE>,
    pub irqs: ArrayVec<u32, NR_IRQ>,

    /// Address of the grant table within the owner's address space (set by
    /// `SYS_SETGRANT`); slice 2.6 starts honoring this.
    pub grant_table: u64,
    /// Number of grant-table entries.
    pub grant_entries: u32,
}

impl Priv {
    /// Empty-slot initializer used to fill the static privilege table at boot.
    pub const EMPTY: Self = Self {
        id: PrivId::new(0),
        proc_nr: None,
        flags: 0,
        trap_mask: 0,
        ipc_to: [0; IPC_MAP_CHUNKS],
        k_call_mask: [0; K_CALL_MASK_CHUNKS],
        notify_pending: [0; IPC_MAP_CHUNKS],
        asyn_pending: [0; IPC_MAP_CHUNKS],
        sig_mgr: NONE,
        io_ranges: ArrayVec::new_const(),
        mem_ranges: ArrayVec::new_const(),
        irqs: ArrayVec::new_const(),
        grant_table: 0,
        grant_entries: 0,
    };
}

