1	//! Endpoints and generation-aware proc-number encoding.
2	//!
3	//! An `Endpoint` is the kernel's name for a process. It encodes both the
4	//! process-table slot (`ProcNr`) and a generation counter (`GenNr`) so that
5	//! a slot reuse after a process exit produces a distinct endpoint. This
6	//! catches stale-endpoint bugs in user-space code.
7	//!
8	//! Mirrors MINIX 3 `include/minix/type.h` (`typedef int endpoint_t`) and
9	//! `include/minix/endpoint.h` (the `_ENDPOINT(g, n)` / `_ENDPOINT_P(e)` /
10	//! `_ENDPOINT_G(e)` macros), with one deliberate ABI deviation: MINIX 4
11	//! uses sign-extension of the low `ENDPOINT_GEN_SHIFT` bits to recover
12	//! negative task slots, rather than MINIX 3's `MAX_NR_TASKS` offset-bias
13	//! trick. The consequence is that `make_endpoint(0, p) != p` for negative
14	//! `p` — use `boot_endpoint(p)` explicitly when constructing an endpoint
15	//! from a kernel-task `ProcNr` constant like `SYSTEM`.
16	
17	use core::fmt;
18	
19	/// Kernel-assigned identifier for a process; encodes generation + proc_nr.
20	///
21	/// Stays an `i32` alias because it is wire-format: passed through registers
22	/// on the IPC trap and stored in `Message::m_source`. The strongly-typed
23	/// process and privilege indices live in [`ProcNr`] and [`PrivId`].
24	pub type Endpoint = i32;
25	
26	/// Generation counter — bumped when a process slot is reused.
27	pub type GenNr = i32;
28	
29	/// Index into the process table. Task slots are negative (`SYSTEM = -2`, …);
30	/// user-process slots are non-negative.
31	///
32	/// Wraps an `i32` rather than aliasing it so the compiler can distinguish a
33	/// proc-table index from an [`Endpoint`] or a raw register value. Use
34	/// [`ProcNr::new`] for construction and [`ProcNr::get`] when an `i32` is
35	/// needed (e.g. bit-ops or casts to `usize`).
36	#[repr(transparent)]
37	#[derive(Copy, Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
38	pub struct ProcNr(i32);
39	
40	impl ProcNr {
41	    pub const fn new(n: i32) -> Self {
42	        Self(n)
43	    }
44	    pub const fn get(self) -> i32 {
45	        self.0
46	    }
47	    pub const fn is_task(self) -> bool {
48	        self.0 < 0
49	    }
50	}
51	
52	impl fmt::Display for ProcNr {
53	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
54	        write!(f, "{}", self.0)
55	    }
56	}
57	
58	/// Index into the privilege table. Sized to cover `NR_SYS_PROCS` slots; each
59	/// system (privileged) process has its own slot, and all non-system user
60	/// processes share one. Mirrors MINIX 3 `priv.h`'s `s_id` field.
61	#[repr(transparent)]
62	#[derive(Copy, Clone, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
63	pub struct PrivId(u16);
64	
65	impl PrivId {
66	    pub const fn new(n: u16) -> Self {
67	        Self(n)
68	    }
69	    pub const fn get(self) -> u16 {
70	        self.0
71	    }
72	    pub const fn as_usize(self) -> usize {
73	        self.0 as usize
74	    }
75	}
76	
77	impl fmt::Display for PrivId {
78	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
79	        write!(f, "{}", self.0)
80	    }
81	}
82	
83	/// MINIX 3 spelling of [`PrivId`]; kept as a type alias for code that reads
84	/// closer to the reference (e.g. translating `sys_id_t s_id`). The two names
85	/// are interchangeable.
86	pub type SysId = PrivId;
87	
88	/// Width of the proc-number field within an endpoint, in bits. Generation
89	/// occupies the bits above this.
90	pub const ENDPOINT_GEN_SHIFT: i32 = 15;
91	
92	/// Mask covering the proc-number field of an endpoint.
93	pub const ENDPOINT_PROC_MASK: i32 = (1 << ENDPOINT_GEN_SHIFT) - 1;
94	
95	/// Highest positive proc-number representable at generation zero (one less
96	/// than the sign-bit boundary of the proc field). Sentinel endpoints live
97	/// just below this so they decode to gen 0 with proc-numbers well outside
98	/// any plausible `NR_PROCS`. Mirrors MINIX 3's `_ENDPOINT_SLOT_TOP`.
99	pub const ENDPOINT_SLOT_TOP: ProcNr = ProcNr::new((1 << (ENDPOINT_GEN_SHIFT - 1)) - 1);
100	
101	/// Special endpoint matching any sender (used as the `src` argument to
102	/// `RECEIVE`). Always at generation zero.
103	pub const ANY: Endpoint = make_endpoint(0, ENDPOINT_SLOT_TOP);
104	
105	/// Special endpoint meaning "no process". Always at generation zero.
106	pub const NONE: Endpoint = make_endpoint(0, ProcNr::new(ENDPOINT_SLOT_TOP.get() - 1));
107	
108	/// Special endpoint referring to the calling process itself. Always at
109	/// generation zero.
110	pub const SELF: Endpoint = make_endpoint(0, ProcNr::new(ENDPOINT_SLOT_TOP.get() - 2));
111	
112	/// Encode `(generation, proc_nr)` into an endpoint.
113	pub const fn make_endpoint(g: GenNr, p: ProcNr) -> Endpoint {
114	    (g << ENDPOINT_GEN_SHIFT) | (p.get() & ENDPOINT_PROC_MASK)
115	}
116	
117	/// Extract the process-table slot number from an endpoint, sign-extending
118	/// the lower `ENDPOINT_GEN_SHIFT` bits so that task slots come back negative.
119	pub const fn endpoint_proc(e: Endpoint) -> ProcNr {
120	    let masked = e & ENDPOINT_PROC_MASK;
121	    let sign_bit = 1 << (ENDPOINT_GEN_SHIFT - 1);
122	    let signed = if masked & sign_bit != 0 {
123	        masked | !ENDPOINT_PROC_MASK
124	    } else {
125	        masked
126	    };
127	    ProcNr::new(signed)
128	}
129	
130	/// Extract the generation counter from an endpoint.
131	pub const fn endpoint_gen(e: Endpoint) -> GenNr {
132	    e >> ENDPOINT_GEN_SHIFT
133	}
134	
135	#[cfg(test)]
136	mod tests {
137	    use super::*;
138	    use crate::com::NR_PROCS;
139	
140	    #[test]
141	    fn special_endpoints_distinct() {
142	        assert_ne!(ANY, SELF);
143	        assert_ne!(ANY, NONE);
144	        assert_ne!(SELF, NONE);
145	    }
146	
147	    #[test]
148	    fn special_endpoints_have_generation_zero() {
149	        // MINIX 3 invariant: ANY, NONE, SELF must decode to gen 0 so they
150	        // can never collide with a real (gen, proc) endpoint.
151	        for s in [ANY, NONE, SELF] {
152	            assert_eq!(endpoint_gen(s), 0, "sentinel {s:#x} should be at gen 0");
153	        }
154	    }
155	
156	    #[test]
157	    fn special_endpoints_outside_proc_range() {
158	        // Sentinels must decode to proc-numbers well above any plausible
159	        // NR_PROCS so a real gen-0 endpoint never aliases a sentinel.
160	        for s in [ANY, NONE, SELF] {
161	            let p = endpoint_proc(s);
162	            assert!(
163	                p.get() >= NR_PROCS as i32,
164	                "sentinel {s:#x} decoded to proc {p}, inside NR_PROCS={NR_PROCS}"
165	            );
166	        }
167	    }
168	
169	    #[test]
170	    fn encode_decode_positive_proc() {
171	        let e = make_endpoint(3, ProcNr::new(7));
172	        assert_eq!(endpoint_gen(e), 3);
173	        assert_eq!(endpoint_proc(e), ProcNr::new(7));
174	    }
175	
176	    #[test]
177	    fn encode_decode_negative_proc() {
178	        // Task endpoints have negative proc numbers (SYSTEM=-2, IDLE=-4, …).
179	        let e = make_endpoint(1, ProcNr::new(-2));
180	        assert_eq!(endpoint_gen(e), 1);
181	        assert_eq!(endpoint_proc(e), ProcNr::new(-2));
182	    }
183	
184	    #[test]
185	    fn encode_decode_generation_zero() {
186	        let e = make_endpoint(0, ProcNr::new(11));
187	        assert_eq!(endpoint_gen(e), 0);
188	        assert_eq!(endpoint_proc(e), ProcNr::new(11));
189	    }
190	
191	    #[test]
192	    fn proc_field_isolated_from_gen_field() {
193	        // Bumping generation must not change the decoded proc_nr.
194	        for g in 0..8 {
195	            let e = make_endpoint(g, ProcNr::new(5));
196	            assert_eq!(endpoint_proc(e), ProcNr::new(5), "gen={g}");
197	        }
198	    }
199	
200	    #[test]
201	    fn procnr_get_round_trip() {
202	        for n in [-5_i32, -1, 0, 1, 42, 1023] {
203	            assert_eq!(ProcNr::new(n).get(), n);
204	        }
205	    }
206	
207	    #[test]
208	    fn procnr_is_task() {
209	        assert!(ProcNr::new(-2).is_task());
210	        assert!(ProcNr::new(-5).is_task());
211	        assert!(!ProcNr::new(0).is_task());
212	        assert!(!ProcNr::new(11).is_task());
213	    }
214	
215	    #[test]
216	    fn priv_id_round_trips() {
217	        for n in [0_u16, 1, 15, 63] {
218	            let p = PrivId::new(n);
219	            assert_eq!(p.get(), n);
220	            assert_eq!(p.as_usize(), n as usize);
221	        }
222	    }
223	
224	    #[test]
225	    fn priv_id_and_sys_id_alias() {
226	        // SysId is the MINIX-3 spelling of PrivId; they must be identical.
227	        let a: PrivId = PrivId::new(7);
228	        let b: SysId = a;
229	        assert_eq!(a, b);
230	    }
231	}
