        0x0a82e883a194f07b,
        0x67cf3d9d378a806f,
        0xe304acdfc50c3c62,
    ],
    revision: 0,
    response: AtomicU64::new(0),
};

// --- Paging mode (request only) -----------------------------------------

#[repr(C)]
struct PagingModeRequest {
    id: [u64; 4],
    revision: u64,
    response: AtomicU64,
    mode: u64,
    max_mode: u64,
    min_mode: u64,
}

#[used]
#[unsafe(link_section = ".limine_requests")]
static PAGING_MODE_REQUEST: PagingModeRequest = PagingModeRequest {
    id: [
        0xc7b1dd30df4c8b88,
        0x0a82e883a194f07b,
        0x95c1a0edab0944cb,
        0xa4e5cb3842f7488a,
    ],
