/// Install `root_pa` as TTBR0_EL1 and program the TTBR0-side fields of
/// TCR_EL1 (T0SZ=16 → 48-bit VA, IRGN0=ORGN0=WBWA, SH0=Inner, TG0=4 KiB,
/// EPD0=0). TTBR1 fields are preserved.
///
/// SAFETY: must be called with interrupts masked. `root_pa` must point at a
/// valid L0 page table.
pub unsafe fn activate_user_ttbr0(root_pa: u64) {
    // Read-modify-write TCR_EL1, clearing only the `*0` field-set bits.
    //
    //   T0SZ  bits [5:0]
    //   EPD0  bit  7
    //   IRGN0 bits [9:8]
    //   ORGN0 bits [11:10]
    //   SH0   bits [13:12]
    //   TG0   bits [15:14]
    //
    // Mask = 0xC03F | 0x080 = 0x000_0000_0000_FCBF
    const TTBR0_FIELDS_MASK: u64 = 0xFCBF;
    const TCR_T0SZ_16: u64 = 16; // 64 - 48 = 16
    const TCR_EPD0_OFF: u64 = 0 << 7;
    const TCR_IRGN0_WBWA: u64 = 0b01 << 8;
    const TCR_ORGN0_WBWA: u64 = 0b01 << 10;
    const TCR_SH0_INNER: u64 = 0b11 << 12;
    const TCR_TG0_4K: u64 = 0b00 << 14;
    const TTBR0_FIELDS_VAL: u64 = TCR_T0SZ_16
        | TCR_EPD0_OFF
        | TCR_IRGN0_WBWA
        | TCR_ORGN0_WBWA
        | TCR_SH0_INNER
        | TCR_TG0_4K;

    // SAFETY: TTBR0_EL1, TCR_EL1, and TLB-maintenance ops are EL1-only and
    // touch no normal memory. We mask off only TTBR0 fields, leaving every
    // TTBR1-side bit Limine programmed untouched.
    unsafe {
        let tcr: u64;
        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
        let new_tcr = (tcr & !TTBR0_FIELDS_MASK) | TTBR0_FIELDS_VAL;

        asm!(
            "msr ttbr0_el1, {root}",
            "msr tcr_el1, {tcr}",
            "isb",
            "tlbi vmalle1",
            "dsb ish",
            "isb",
            root = in(reg) root_pa,
            tcr = in(reg) new_tcr,
            options(nomem, nostack, preserves_flags),
        );
    }
}

